import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Auth And Data Residency","description":"","frontmatter":{},"headers":[],"relativePath":"admin/auth-data-residency.md","filePath":"admin/auth-data-residency.md","lastUpdated":null}'),n={name:"admin/auth-data-residency.md"};function l(d,a,o,r,h,p){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="auth-and-data-residency" tabindex="-1">Auth And Data Residency <a class="header-anchor" href="#auth-and-data-residency" aria-label="Permalink to &quot;Auth And Data Residency&quot;">​</a></h1><p>Autofac protects product APIs with JWT bearer authentication and role-based authorization. Health probes, auth discovery/dev-token endpoints, and signed integration webhooks remain anonymous by design.</p><h2 id="authentication-modes" tabindex="-1">Authentication modes <a class="header-anchor" href="#authentication-modes" aria-label="Permalink to &quot;Authentication modes&quot;">​</a></h2><h3 id="enterprise-oidc-jwt" tabindex="-1">Enterprise OIDC/JWT <a class="header-anchor" href="#enterprise-oidc-jwt" aria-label="Permalink to &quot;Enterprise OIDC/JWT&quot;">​</a></h3><p>Configure the API to validate tokens from your identity provider.</p><p>Microsoft Entra ID example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Authority</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://login.microsoftonline.com/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tenant-id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/v2.0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Audience</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">api://autofac</span></span></code></pre></div><p>Keycloak example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Authority</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://keycloak.example.com/realms/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">realm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Audience</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac-api</span></span></code></pre></div><p>Autofac normalizes role claims from <code>role</code>, <code>roles</code>, <code>groups</code>, and the standard .NET role claim type. Configure additional claim names when needed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleClaimTypes__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">roles</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleClaimTypes__1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">groups</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__NameClaimTypes__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">preferred_username</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__NameClaimTypes__1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">email</span></span></code></pre></div><p>Map external groups to Autofac roles:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleMappings__autofac_viewers__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Viewer</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleMappings__autofac_operators__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Operator</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleMappings__autofac_approvers__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Approver</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__RoleMappings__autofac_admins__0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Admin</span></span></code></pre></div><h3 id="symmetric-jwt-for-local-stacks" tabindex="-1">Symmetric JWT for local stacks <a class="header-anchor" href="#symmetric-jwt-for-local-stacks" aria-label="Permalink to &quot;Symmetric JWT for local stacks&quot;">​</a></h3><p>Local and manual-test stacks can use a development signing key:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__SecretKey</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac-dev-manual-testing-key-2026</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Issuer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac-dev</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__Audience</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac-dev</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__DevTokensEnabled</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><p>Do not enable development tokens in production.</p><h3 id="development-identity-mode" tabindex="-1">Development identity mode <a class="header-anchor" href="#development-identity-mode" aria-label="Permalink to &quot;Development identity mode&quot;">​</a></h3><p><code>appsettings.Development.json</code> can authenticate requests without a bearer token as <code>dev:admin</code> when <code>ASPNETCORE_ENVIRONMENT=Development</code>. Disable this in shared development environments that need explicit bearer tokens:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Jwt__DevIdentityEnabled</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">false</span></span></code></pre></div><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Access</th></tr></thead><tbody><tr><td><code>Viewer</code></td><td>Read workflows, runs, approvals, templates, agents, and skills.</td></tr><tr><td><code>Operator</code></td><td>Viewer access plus workflow import/validation, run start/cancel/recover, policy simulation, and artifact upload.</td></tr><tr><td><code>Approver</code></td><td>Viewer access plus approval decisions.</td></tr><tr><td><code>Admin</code></td><td>Operator and approver access plus workflow publish, settings, and policy-rule management.</td></tr></tbody></table><h2 id="data-residency-boundaries" tabindex="-1">Data residency boundaries <a class="header-anchor" href="#data-residency-boundaries" aria-label="Permalink to &quot;Data residency boundaries&quot;">​</a></h2><p>The default self-hosted deployment keeps workflow definitions, runs, approvals, audit records, run context, and outbox state in the configured PostgreSQL database.</p><p>Artifact bytes stay in the configured storage provider:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Boundary</th></tr></thead><tbody><tr><td><code>filesystem</code></td><td>Files under <code>Storage:RootPath</code>.</td></tr><tr><td><code>s3</code></td><td>Bucket and region configured by the operator.</td></tr></tbody></table><p>The default <code>WorkflowRuntime:Mode=Autofac</code> does not require Camunda. Camunda settings are consumed only when <code>WorkflowRuntime:Mode=Camunda</code>.</p><h2 id="external-data-flows" tabindex="-1">External data flows <a class="header-anchor" href="#external-data-flows" aria-label="Permalink to &quot;External data flows&quot;">​</a></h2><p>Data leaves the self-hosted boundary only through explicitly enabled integrations and model providers:</p><ul><li>GitHub, Jira, Slack, and Teams connectors.</li><li>Model-provider endpoints.</li><li>Artifact storage if it is outside the host or cluster.</li><li>Telemetry endpoints such as OTLP collectors.</li></ul><p>For German or EU residency requirements, choose customer-approved regions for Postgres, artifacts, and model endpoints, and verify connector tenant boundaries.</p><h2 id="production-checklist" tabindex="-1">Production checklist <a class="header-anchor" href="#production-checklist" aria-label="Permalink to &quot;Production checklist&quot;">​</a></h2><ul><li>Disable dev identity and dev tokens.</li><li>Use real JWT/OIDC authority and audience settings.</li><li>Map enterprise roles deliberately.</li><li>Store identity-provider secrets outside the repository.</li><li>Document the configured data boundary.</li><li>Review enabled integrations before production traffic.</li><li>Confirm evidence packs do not contain unexpected sensitive content.</li></ul>`,33)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
